class Game {
    constructor(canvas, ctx) {
        this.canvas = canvas;
        this.ctx = ctx;
        this.width = canvas.width;
        this.height = canvas.height;

        this.input = new Input();
        this.physics = new Physics();

        this.player = new Player(100, 300);
        this.platforms = [];
        this.particles = [];

        this.score = 0;
        this.gameOver = false;

        this.setupLevel();
        this.bindEvents();
    }

    setupLevel() {
        // Ground platforms
        this.platforms.push(new Platform(0, 550, 800, 50, '#2d5016'));

        // Jumping platforms
        this.platforms.push(new Platform(200, 450, 150, 20, '#4a7c2e'));
        this.platforms.push(new Platform(450, 350, 150, 20, '#4a7c2e'));
        this.platforms.push(new Platform(100, 250, 100, 20, '#4a7c2e'));
        this.platforms.push(new Platform(600, 200, 120, 20, '#4a7c2e'));
        this.platforms.push(new Platform(300, 150, 100, 20, '#4a7c2e'));

        // Moving platform
        this.platforms.push(new Platform(350, 400, 100, 20, '#6b9b3d', true, 2));
    }

    bindEvents() {
        window.addEventListener('keydown', (e) => {
            if (e.code === 'KeyR') {
                this.restart();
            }
        });
    }

    start() {
        this.lastTime = performance.now();
        requestAnimationFrame((timestamp) => this.loop(timestamp));
    }

    loop(timestamp) {
        const deltaTime = (timestamp - this.lastTime) / 1000;
        this.lastTime = timestamp;

        this.update(deltaTime);
        this.render();

        if (!this.gameOver) {
            requestAnimationFrame((timestamp) => this.loop(timestamp));
        }
    }

    update(deltaTime) {
        // Cap delta time to prevent physics explosions
        const dt = Math.min(deltaTime, 0.1);

        // Update input
        this.input.update();

        // Update player
        this.player.update(dt, this.input, this.platforms);

        // Update platforms (for moving ones)
        this.platforms.forEach(platform => platform.update(dt));

        // Update particles
        this.particles = this.particles.filter(p => p.life > 0);
        this.particles.forEach(p => p.update(dt));

        // Check if player fell off screen
        if (this.player.y > this.height + 100) {
            this.restart();
        }

        // Update score based on height
        const heightScore = Math.floor((550 - this.player.y) / 10);
        if (heightScore > this.score) {
            this.score = heightScore;
            document.getElementById('score').textContent = this.score;
        }

        // Spawn trail particles
        if (Math.abs(this.player.velocityX) > 50 || Math.abs(this.player.velocityY) > 50) {
            if (Math.random() < 0.3) {
                this.particles.push(new Particle(
                    this.player.x + this.player.width / 2,
                    this.player.y + this.player.height,
                    (Math.random() - 0.5) * 20,
                    -Math.random() * 30,
                    '#fff',
                    0.5
                ));
            }
        }
    }

    render() {
        // Clear canvas
        this.ctx.fillStyle = '#87CEEB';
        this.ctx.fillRect(0, 0, this.width, this.height);

        // Draw clouds (decorative)
        this.drawCloud(100, 80, 0.8);
        this.drawCloud(500, 120, 0.6);
        this.drawCloud(700, 60, 0.7);

        // Draw platforms
        this.platforms.forEach(platform => platform.render(this.ctx));

        // Draw particles
        this.particles.forEach(p => p.render(this.ctx));

        // Draw player
        this.player.render(this.ctx);
    }

    drawCloud(x, y, scale) {
        this.ctx.fillStyle = 'rgba(255, 255, 255, 0.8)';
        this.ctx.beginPath();
        this.ctx.arc(x, y, 30 * scale, 0, Math.PI * 2);
        this.ctx.arc(x + 25 * scale, y - 10 * scale, 35 * scale, 0, Math.PI * 2);
        this.ctx.arc(x + 50 * scale, y, 30 * scale, 0, Math.PI * 2);
        this.ctx.fill();
    }

    restart() {
        this.player = new Player(100, 300);
        this.score = 0;
        this.particles = [];
        document.getElementById('score').textContent = '0';
        this.gameOver = false;
    }
}

