class Player {
    constructor(x, y) {
        this.x = x;
        this.y = y;
        this.width = 32;
        this.height = 32;
        this.velocityX = 0;
        this.velocityY = 0;
        this.speed = 250;
        this.jumpPower = 500;
        this.gravity = 1200;
        this.friction = 0.85;
        this.onGround = false;
        this.facingRight = true;

        // Animation
        this.animTimer = 0;
        this.frame = 0;
    }

    update(dt, input, platforms) {
        // Horizontal movement
        if (input.isPressed('ArrowLeft') || input.isPressed('KeyA')) {
            this.velocityX -= this.speed * dt * 4;
            this.facingRight = false;
        }
        if (input.isPressed('ArrowRight') || input.isPressed('KeyD')) {
            this.velocityX += this.speed * dt * 4;
            this.facingRight = true;
        }

        // Apply friction
        this.velocityX *= this.friction;

        // Cap horizontal speed
        this.velocityX = Math.max(-this.speed, Math.min(this.speed, this.velocityX));

        // Jumping
        if ((input.isPressed('Space') || input.isPressed('ArrowUp') || input.isPressed('KeyW')) && this.onGround) {
            this.velocityY = -this.jumpPower;
            this.onGround = false;
        }

        // Apply gravity
        this.velocityY += this.gravity * dt;

        // Update position
        this.x += this.velocityX * dt;
        this.y += this.velocityY * dt;

        // Collision detection
        this.onGround = false;
        platforms.forEach(platform => this.checkCollision(platform));

        // Screen boundaries
        if (this.x < 0) {
            this.x = 0;
            this.velocityX = 0;
        }
        if (this.x + this.width > 800) {
            this.x = 800 - this.width;
            this.velocityX = 0;
        }

        // Animation
        this.animTimer += dt;
        if (this.animTimer > 0.1) {
            this.frame = (this.frame + 1) % 4;
            this.animTimer = 0;
        }
    }

    checkCollision(platform) {
        if (this.x < platform.x + platform.width &&
            this.x + this.width > platform.x &&
            this.y < platform.y + platform.height &&
            this.y + this.height > platform.y) {

            // Check if landing on top
            if (this.velocityY > 0 && this.y + this.height - this.velocityY * 0.016 <= platform.y) {
                this.y = platform.y - this.height;
                this.velocityY = 0;
                this.onGround = true;

                // Move with platform if it's moving
                if (platform.velocityX !== 0) {
                    this.x += platform.velocityX * 0.016;
                }
            } else if (this.velocityY < 0 && this.y - this.velocityY * 0.016 >= platform.y + platform.height) {
                // Hit head on bottom
                this.y = platform.y + platform.height;
                this.velocityY = 0;
            } else if (this.velocityX > 0) {
                // Hit left side
                this.x = platform.x - this.width;
                this.velocityX = 0;
            } else if (this.velocityX < 0) {
                // Hit right side
                this.x = platform.x + platform.width;
                this.velocityX = 0;
            }
        }
    }

    render(ctx) {
        // Draw player body
        ctx.fillStyle = '#ff4444';
        ctx.fillRect(this.x, this.y, this.width, this.height);

        // Draw eyes (direction based)
        ctx.fillStyle = '#fff';
        const eyeOffset = this.facingRight ? 4 : -4;
        ctx.fillRect(this.x + 8 + eyeOffset, this.y + 6, 6, 6);
        ctx.fillRect(this.x + 18 + eyeOffset, this.y + 6, 6, 6);

        // Draw pupils
        ctx.fillStyle = '#000';
        ctx.fillRect(this.x + 10 + eyeOffset, this.y + 8, 2, 2);
        ctx.fillRect(this.x + 20 + eyeOffset, this.y + 8, 2, 2);

        // Draw simple running animation legs
        if (Math.abs(this.velocityX) > 10) {
            ctx.fillStyle = '#cc3333';
            const legOffset = Math.sin(this.frame * Math.PI / 2) * 4;
            ctx.fillRect(this.x + 6, this.y + this.height - 4, 8, 4 + legOffset);
            ctx.fillRect(this.x + 18, this.y + this.height - 4, 8, 4 - legOffset);
        }
    }
}

