class Platform {
    constructor(x, y, width, height, color, isMoving = false, moveSpeed = 0) {
        this.x = x;
        this.y = y;
        this.width = width;
        this.height = height;
        this.color = color;
        this.isMoving = isMoving;
        this.moveSpeed = moveSpeed;
        this.velocityX = moveSpeed;
        this.startX = x;
        this.moveRange = 150;
    }

    update(dt) {
        if (this.isMoving) {
            this.x += this.velocityX * dt;

            // Reverse direction at range limits
            if (this.x > this.startX + this.moveRange) {
                this.velocityX = -this.moveSpeed;
            } else if (this.x < this.startX - this.moveRange) {
                this.velocityX = this.moveSpeed;
            }
        }
    }

    render(ctx) {
        // Main platform body
        ctx.fillStyle = this.color;
        ctx.fillRect(this.x, this.y, this.width, this.height);

        // Top highlight
        ctx.fillStyle = 'rgba(255, 255, 255, 0.3)';
        ctx.fillRect(this.x, this.y, this.width, 4);

        // Side shadow
        ctx.fillStyle = 'rgba(0, 0, 0, 0.2)';
        ctx.fillRect(this.x + this.width - 4, this.y, 4, this.height);
        ctx.fillRect(this.x, this.y + this.height - 4, this.width, 4);

        // Grass detail on top
        if (this.color === '#2d5016' || this.color === '#4a7c2e') {
            ctx.fillStyle = '#5a8c3e';
            for (let i = 0; i < this.width; i += 20) {
                ctx.fillRect(this.x + i, this.y - 4, 8, 4);
            }
        }
    }
}

