class Physics {
    constructor() {
        this.gravity = 1200;
    }

    applyGravity(entity, dt) {
        entity.velocityY += this.gravity * dt;
    }

    checkCollision(rect1, rect2) {
        return rect1.x < rect2.x + rect2.width &&
               rect1.x + rect1.width > rect2.x &&
               rect1.y < rect2.y + rect2.height &&
               rect1.y + rect1.height > rect2.y;
    }

    resolveCollision(entity, platform) {
        // Basic AABB resolution
        const overlapX = (entity.width + platform.width) / 2 - Math.abs(entity.x - platform.x);
        const overlapY = (entity.height + platform.height) / 2 - Math.abs(entity.y - platform.y);

        if (overlapX < overlapY) {
            // Horizontal collision
            if (entity.x < platform.x) {
                entity.x = platform.x - entity.width;
            } else {
                entity.x = platform.x + platform.width;
            }
            entity.velocityX = 0;
        } else {
            // Vertical collision
            if (entity.y < platform.y) {
                entity.y = platform.y - entity.height;
                entity.onGround = true;
            } else {
                entity.y = platform.y + platform.height;
            }
            entity.velocityY = 0;
        }
    }
}

